+        runTest(TestShiftOpOnFloatingVector::testROR,  "ROR");
+        runTest(TestShiftOpOnFloatingVector::testLSHL, "LSHL");
+        runTest(TestShiftOpOnFloatingVector::testLSHR, "LSHR");
+        runTest(TestShiftOpOnFloatingVector::testASHR, "ASHR");
+    }
